import pytest
from levenshtein import levenshtein


# ---------------------------------------------------------------------------
# Happy path – typical, well-formed inputs
# ---------------------------------------------------------------------------

class TestHappyPath:
    def test_identical_strings(self):
        assert levenshtein("kitten", "kitten") == 0

    def test_single_substitution(self):
        # kitten → sitten (k→s)
        assert levenshtein("kitten", "sitten") == 1

    def test_classic_kitten_sitting(self):
        # kitten → sitting  (distance = 3)
        assert levenshtein("kitten", "sitting") == 3

    def test_classic_saturday_sunday(self):
        assert levenshtein("saturday", "sunday") == 3

    def test_single_insertion(self):
        assert levenshtein("abc", "abcd") == 1

    def test_single_deletion(self):
        assert levenshtein("abcd", "abc") == 1

    def test_single_substitution_short(self):
        assert levenshtein("cat", "bat") == 1

    def test_completely_different_same_length(self):
        assert levenshtein("abc", "xyz") == 3

    def test_completely_different_different_length(self):
        assert levenshtein("abcd", "xyz") == 4

    def test_longer_common_words(self):
        assert levenshtein("intention", "execution") == 5

    def test_case_sensitive(self):
        # 'A' != 'a', so distance should be 1
        assert levenshtein("ABC", "abc") == 3

    def test_unicode_identical(self):
        assert levenshtein("café", "café") == 0

    def test_unicode_substitution(self):
        assert levenshtein("café", "cave") == 2

    def test_numbers_as_strings(self):
        assert levenshtein("12345", "12345") == 0

    def test_numbers_with_difference(self):
        assert levenshtein("12345", "1245") == 1


